.game-container {
    max-width: 800px;
    margin: 40px auto;
    padding: 20px;
    border: 1px solid #ccc;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
}

.track-controls {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
}

.track-control {
    width: 25%;
    margin: 10px;
}

.effect-controls {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
}

.effect-control {
    width: 25%;
    margin: 10px;
}
